using UnityEngine;
using System.Collections.Generic;

// Serializable classes for JSON
[System.Serializable]
public class PlayerData
{
    public string playerName;
    public int health;
    public int level;
    public float experience;
    public int score;
    public Vector3 position;
    public List<string> inventory;

    public PlayerData()
    {
        inventory = new List<string>();
    }
}

[System.Serializable]
public class GameData
{
    public PlayerData player;
    public List<EnemyData> enemies;
    public int currentLevel;
    public float playTime;
    public string saveTime;
}

[System.Serializable]
public class EnemyData
{
    public string name;
    public int health;
    public int attack;
    public bool isAlive;
    public float[] position;
}

public class JSONExample : MonoBehaviour
{
    void Start()
    {
        // Test JSON
        if (Input.GetKeyDown(KeyCode.J))
        {
            SaveJSONTest();
        }
        if (Input.GetKeyDown(KeyCode.K))
        {
            LoadJSONTest();
        }
    }

    // --- Saving to JSON ---

    public void SaveGameData()
    {
        // Create sample data
        PlayerData player = new PlayerData();
        player.playerName = "Hero";
        player.health = 100;
        player.level = 5;
        player.experience = 250f;
        player.score = 1200;
        player.position = new Vector3(10, 5, 0);
        player.inventory.AddRange(new string[] { "Sword", "Shield", "Potion" });

        // Create enemies
        List<EnemyData> enemies = new List<EnemyData>();

        EnemyData enemy1 = new EnemyData();
        enemy1.name = "Goblin";
        enemy1.health = 30;
        enemy1.attack = 8;
        enemy1.isAlive = true;
        enemy1.position = new float[] { 5, 2, 0 };
        enemies.Add(enemy1);

        EnemyData enemy2 = new EnemyData();
        enemy2.name = "Orc";
        enemy2.health = 50;
        enemy2.attack = 12;
        enemy2.isAlive = true;
        enemy2.position = new float[] { -3, 1, 0 };
        enemies.Add(enemy2);

        // Create game data
        GameData gameData = new GameData();
        gameData.player = player;
        gameData.enemies = enemies;
        gameData.currentLevel = 3;
        gameData.playTime = 123.5f;
        gameData.saveTime = System.DateTime.Now.ToString();

        // Serialize to JSON
        string json = JsonUtility.ToJson(gameData, true);

        // Save to PlayerPrefs
        PlayerPrefs.SetString("GameSave", json);
        PlayerPrefs.Save();

        Debug.Log("Game saved to JSON!");
        Debug.Log(json);
    }

    // --- Loading from JSON ---

    public void LoadGameData()
    {
        if (PlayerPrefs.HasKey("GameSave"))
        {
            string json = PlayerPrefs.GetString("GameSave");

            // Deserialize from JSON
            GameData gameData = JsonUtility.FromJson<GameData>(json);

            if (gameData != null)
            {
                Debug.Log("=== Loaded Game Data ===");
                Debug.Log("Player: " + gameData.player.playerName);
                Debug.Log("Health: " + gameData.player.health);
                Debug.Log("Level: " + gameData.player.level);
                Debug.Log("Score: " + gameData.player.score);
                Debug.Log("Level: " + gameData.currentLevel);
                Debug.Log("Play Time: " + gameData.playTime);
                Debug.Log("Saved at: " + gameData.saveTime);

                Debug.Log("Inventory:");
                foreach (string item in gameData.player.inventory)
                {
                    Debug.Log("  - " + item);
                }

                Debug.Log("Enemies:");
                foreach (EnemyData enemy in gameData.enemies)
                {
                    Debug.Log("  - " + enemy.name + " (HP: " + enemy.health + ", Alive: " + enemy.isAlive + ")");
                }
            }
            else
            {
                Debug.LogError("Failed to parse JSON!");
            }
        }
        else
        {
            Debug.Log("No save data found!");
        }
    }

    // --- Utility methods ---

    public void SaveJSONTest()
    {
        SaveGameData();
        Debug.Log("JSON saved! Press K to load.");
    }

    public void LoadJSONTest()
    {
        LoadGameData();
    }

    // --- Example: Saving a simple object ---

    public void SaveSimpleData()
    {
        PlayerData player = new PlayerData();
        player.playerName = "Simple Hero";
        player.health = 100;

        string json = JsonUtility.ToJson(player);
        PlayerPrefs.SetString("SimpleSave", json);
        PlayerPrefs.Save();

        Debug.Log("Simple data saved!");
    }

    public void LoadSimpleData()
    {
        if (PlayerPrefs.HasKey("SimpleSave"))
        {
            string json = PlayerPrefs.GetString("SimpleSave");
            PlayerData player = JsonUtility.FromJson<PlayerData>(json);

            Debug.Log("Loaded: " + player.playerName + " (HP: " + player.health + ")");
        }
    }
}

