using UnityEngine;

public class JSONError : MonoBehaviour
{
    void Start()
    {
        // Forgetting [System.Serializable] on the class
        PlayerData player = new PlayerData();
        string json = JsonUtility.ToJson(player);  // Returns "{}"!
        Debug.Log(json);
    }

    // Not serializable!
    class PlayerData
    {
        public string name;
        public int health;
    }
}

phase2.explanation:
Without `[System.Serializable]`, Unity can't serialize the class.

**The fix:**
```csharp
[System.Serializable]  // ← Add this!
class PlayerData
{
    public string name;
    public int health;
}
```

**Sharp-chan says:**
"Always mark classes with `[System.Serializable]` for JSON serialization."
